/**
 * Returns current budget utilization for a mandate
 * @summary Get budget state
 */
export const getGetBudgetUrl = (id: string) => {
  return `/api/gauth/mgmt/v1/mandates/${id}/budget`;
};

export const getBudget = async (
  id: string,
  options?: RequestInit,
): Promise<BudgetDetail> => {
  return customFetch<BudgetDetail>(getGetBudgetUrl(id), {
    ...options,
    method: "GET",
  });
};

export const getGetBudgetQueryKey = (id: string) => {
  return [`/api/gauth/mgmt/v1/mandates/${id}/budget`] as const;
};

export const getGetBudgetQueryOptions = <
  TData = Awaited<ReturnType<typeof getBudget>>,
  TError = ErrorType<ManagementErrorResponse>,
>(
  id: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getBudget>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetBudgetQueryKey(id);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getBudget>>> = ({
    signal,
  }) => getBudget(id, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!id,
    ...queryOptions,
  } as UseQueryOptions<Awaited<ReturnType<typeof getBudget>>, TError, TData> & {
    queryKey: QueryKey;
  };
};

export type GetBudgetQueryResult = NonNullable<
  Awaited<ReturnType<typeof getBudget>>
>;
export type GetBudgetQueryError = ErrorType<ManagementErrorResponse>;

/**
 * @summary Get budget state
 */

export function useGetBudget<
  TData = Awaited<ReturnType<typeof getBudget>>,
  TError = ErrorType<ManagementErrorResponse>,
>(
  id: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getBudget>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetBudgetQueryOptions(id, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

